export class CheckoutService {
    /**
     * Get Runtime
     * Return popup metadata, products, buyer form, and ticketing steps for anonymous checkout.
     *
     * Fully public endpoint (no JWT). Only serves sale_type=direct active popups.
     * Rate-limited 120/min/IP.
     * @param data The data for the request.
     * @param data.slug
     * @param data.xTenantId
     * @returns CheckoutRuntimeResponse Successful Response
     * @throws ApiError
     */
    public static getRuntime(data: CheckoutGetRuntimeData): CancelablePromise<CheckoutGetRuntimeResponse> {
        return __request(OpenAPI, {
            method: 'GET',
            url: '/api/v1/checkout/{slug}/runtime',
            path: {
                slug: data.slug
            },
            headers: {
                'X-Tenant-Id': data.xTenantId
            },
            errors: {
                422: 'Validation Error'
            }
        });
    }
    
    /**
     * Get Checkout Share Meta
     * Unauthenticated checkout metadata for social/OpenGraph share previews.
     *
     * Social crawlers send no JWT, so this route is intentionally public. It
     * exposes only the popup name, tagline, location and cover image — never
     * products, buyer forms or ticketing steps.
     *
     * Only active ``sale_type=direct`` popups for the resolved tenant are
     * returned; everything else gets an opaque 404.
     * @param data The data for the request.
     * @param data.slug
     * @param data.xTenantId
     * @returns CheckoutShareMeta Successful Response
     * @throws ApiError
     */
    public static getCheckoutShareMeta(data: CheckoutGetCheckoutShareMetaData): CancelablePromise<CheckoutGetCheckoutShareMetaResponse> {
        return __request(OpenAPI, {
            method: 'GET',
            url: '/api/v1/checkout/{slug}/share',
            path: {
                slug: data.slug
            },
            headers: {
                'X-Tenant-Id': data.xTenantId
            },
            errors: {
                422: 'Validation Error'
            }
        });
    }
    
    /**
     * Purchase Open Ticketing
     * Create an anonymous open-ticketing payment and return provider checkout data.
     * @param data The data for the request.
     * @param data.slug
     * @param data.requestBody
     * @param data.xTenantId
     * @returns OpenTicketingPurchaseResponse Successful Response
     * @throws ApiError
     */
    public static purchaseOpenTicketing(data: CheckoutPurchaseOpenTicketingData): CancelablePromise<CheckoutPurchaseOpenTicketingResponse> {
        return __request(OpenAPI, {
            method: 'POST',
            url: '/api/v1/checkout/{slug}/purchase',
            path: {
                slug: data.slug
            },
            headers: {
                'X-Tenant-Id': data.xTenantId
            },
            body: data.requestBody,
            mediaType: 'application/json',
            errors: {
                409: "Payment conflict. detail.code is one of: 'pending_payment_exists' (a prior PENDING payment exists and no valid cart continuity proof was supplied — no cancellation attempted); 'concurrent_payment_in_progress' (another checkout is in progress under the same email right now); 'previous_payment_completed' (prior payment was already approved — includes redirect_url when a signing secret and external success URL are both configured).",
                422: 'Validation Error',
                502: "Payment provider error. detail.code='payment_cancel_failed' means the prior pending payment could not be cancelled. Retry the request."
            }
        });
    }
    
    /**
     * Upsert Open Cart
     * Save (create or replace) the anonymous open-checkout cart for an email.
     *
     * Fully public (no JWT), keyed by (popup, email). Returns a signed
     * `restore_token` when the popup configures an open_checkout_signing_secret so
     * the client can later rebuild the cart cross-device. Rate-limited 30/min/IP.
     * @param data The data for the request.
     * @param data.slug
     * @param data.requestBody
     * @param data.xTenantId
     * @returns OpenCartPublic Successful Response
     * @throws ApiError
     */
    public static upsertOpenCart(data: CheckoutUpsertOpenCartData): CancelablePromise<CheckoutUpsertOpenCartResponse> {
        return __request(OpenAPI, {
            method: 'PUT',
            url: '/api/v1/checkout/{slug}/cart',
            path: {
                slug: data.slug
            },
            headers: {
                'X-Tenant-Id': data.xTenantId
            },
            body: data.requestBody,
            mediaType: 'application/json',
            errors: {
                422: 'Validation Error'
            }
        });
    }
    
    /**
     * Restore Open Cart
     * Restore an anonymous cart from a signed link (cid + sig).
     *
     * The cart is served only when the signature matches, so it can never be read
     * by enumerating ids or emails. Requires the popup to have an
     * open_checkout_signing_secret. Rate-limited 60/min/IP.
     * @param data The data for the request.
     * @param data.slug
     * @param data.cid Cart id from the signed restore link
     * @param data.sig HMAC restore token for the cart id
     * @param data.xTenantId
     * @returns OpenCartPublic Successful Response
     * @throws ApiError
     */
    public static restoreOpenCart(data: CheckoutRestoreOpenCartData): CancelablePromise<CheckoutRestoreOpenCartResponse> {
        return __request(OpenAPI, {
            method: 'GET',
            url: '/api/v1/checkout/{slug}/cart',
            path: {
                slug: data.slug
            },
            headers: {
                'X-Tenant-Id': data.xTenantId
            },
            query: {
                cid: data.cid,
                sig: data.sig
            },
            errors: {
                422: 'Validation Error'
            }
        });
    }
    
    /**
     * Release Pending Open
     * Opportunistically release a buyer's own prior PENDING payment on checkout return.
     *
     * Called by the portal on checkout mount before coupon validation or stock display.
     * This frees any coupon/stock/credit holds so the buyer can re-apply their own
     * single-use coupon without a false-invalid error (the circularity fix).
     *
     * Proof: cart continuity HMAC (cid + sig), validated server-side.
     *
     * Response contract (ADR-R3 enumeration-safe):
     * - HTTP 200 {released: false}: invalid/missing proof, no PENDING, or flag disabled.
     * Body is byte-identical across ALL false outcomes to prevent email enumeration.
     * - HTTP 200 {released: true}: PENDING payment cancelled, holds freed.
     * - HTTP 409 previous_payment_completed: race lost — prior payment already approved.
     * - HTTP 502 payment_cancel_failed: SimpleFi unreachable; creation-time backstop remains.
     *
     * Rate-limited 30/min/IP (matching the neighboring cart endpoint).
     * @param data The data for the request.
     * @param data.slug
     * @param data.requestBody
     * @param data.xTenantId
     * @returns PendingReleaseResponse Successful Response
     * @throws ApiError
     */
    public static releasePendingOpen(data: CheckoutReleasePendingOpenData): CancelablePromise<CheckoutReleasePendingOpenResponse> {
        return __request(OpenAPI, {
            method: 'POST',
            url: '/api/v1/checkout/{slug}/pending/release',
            path: {
                slug: data.slug
            },
            headers: {
                'X-Tenant-Id': data.xTenantId
            },
            body: data.requestBody,
            mediaType: 'application/json',
            errors: {
                409: "Payment conflict. detail.code='previous_payment_completed' means the prior PENDING payment was concurrently approved — includes a signed redirect_url when the popup has a signing secret and an external success URL configured.",
                422: 'Validation Error',
                502: "Payment provider error. detail.code='payment_cancel_failed' means the prior pending payment could not be cancelled. Checkout should proceed — creation-time supersede remains as a backstop."
            }
        });
    }
}

